// テスト用フィクスチャ: API呼び出しでundefinedが返るケース
export async function fetchUserProfile(userId: string) {
  const response = await fetch(`/api/users/${userId}/profile`);
  const data = await response.json();
  return data.profile;
}

export function UserProfilePage({ userId }: { userId: string }) {
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    fetchUserProfile(userId).then(setProfile);
  }, [userId]);

  return <div>{profile?.name}</div>;
}

// テスト用フィクスチャ: useEffectでsetStateしてレンダリングが2回走るケース
import { useState, useEffect } from "react";

export function SettingsPage() {
  const [settings, setSettings] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    fetch("/api/settings")
      .then((res) => res.json())
      .then((data) => {
        setSettings(data);
        setIsLoading(false);
      });
  }, []);

  console.log("render", { settings, isLoading });

  return (
    <div>
      {isLoading ? <p>Loading...</p> : <pre>{JSON.stringify(settings)}</pre>}
    </div>
  );
}

// テスト用フィクスチャ: flaky integration test
import { describe, it, expect, beforeAll, afterAll } from "vitest";
import { createTestServer } from "../helpers/server";
import { createTestUser, cleanupTestUsers } from "../helpers/users";

describe("Authentication", () => {
  let server: ReturnType<typeof createTestServer>;

  beforeAll(async () => {
    server = createTestServer();
    await server.start();
  });

  afterAll(async () => {
    await cleanupTestUsers();
    await server.stop();
  });

  it("should login with valid credentials", async () => {
    const user = await createTestUser({ email: "test@example.com", password: "password123" });
    const response = await fetch(`${server.url}/auth/login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: user.email, password: "password123" }),
    });

    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.token).toBeDefined();
  });

  it("should refresh token before expiry", async () => {
    const user = await createTestUser({ email: "refresh@example.com", password: "password123" });
    const loginRes = await fetch(`${server.url}/auth/login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: user.email, password: "password123" }),
    });
    const { token } = await loginRes.json();

    // Wait for token to be near expiry
    await new Promise((r) => setTimeout(r, 1000));

    const refreshRes = await fetch(`${server.url}/auth/refresh`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
    });

    expect(refreshRes.status).toBe(200);
    const refreshData = await refreshRes.json();
    expect(refreshData.token).not.toBe(token);
  });
});

